#!/usr/bin/env python3
# read-only diagnostic: dump the source-hunter + source distribution + status-push fn -> NEW status file (no 409 race)
import os,sys,json,glob,time,subprocess,base64,urllib.request,re
def load_env():
    for p in ("/etc/atlas/autopull.env","/etc/atlas/db.env","/etc/atlas/status.env"):
        if os.path.exists(p):
            for ln in open(p):
                ln=ln.strip()
                if ln.startswith("export "): ln=ln[7:]
                if "=" in ln and not ln.startswith("#"):
                    k,v=ln.split("=",1); k=k.strip()
                    if k and k not in os.environ: os.environ[k]=v.strip().strip('"').strip("'")
load_env()
out={"kind":"srchunt-diag","ts":int(time.time())}
# 1) candidate source-hunter / discovery scripts
cands=[]
for pat in ("*hunter*","*source*","*discover*","*socrata*","*promote*","*geo*"):
    cands+=glob.glob("/opt/atlas/**/"+pat+".py",recursive=True)
cands=sorted(set(cands))
out["scripts"]=[]
for f in cands[:12]:
    try:
        txt=open(f,encoding="utf-8",errors="replace").read()
    except Exception as e:
        txt="ERR "+str(e)
    out["scripts"].append({"path":f,"bytes":len(txt),"head":txt[:1400]})
# 2) systemd timers/services for sources
try:
    u=subprocess.run(["bash","-lc","systemctl list-units --type=service,timer --all --no-pager 2>/dev/null | grep -iE 'atlas|source|hunter|socrata|czds|nrd|channel1' | awk '{print $1,$3,$4}'"],capture_output=True,text=True).stdout
    out["units"]=u[:2500]
except Exception as e: out["units"]="ERR "+str(e)
# 3) DB source distribution
try:
    sys.path.insert(0,"/opt/atlas/importers")
    import socrata_import as si
    c=si.connect_pg(); cur=c.cursor()
    cur.execute("SELECT source, count(*) FROM atlas.business GROUP BY source ORDER BY 2 DESC LIMIT 40")
    out["source_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
    cur.execute("SELECT count(distinct source) FROM atlas.business"); out["source_count"]=int(cur.fetchone()[0])
    # region/state distribution (geo skew)
    try:
        cur.execute("SELECT region, count(*) FROM atlas.business WHERE region IS NOT NULL GROUP BY region ORDER BY 2 DESC LIMIT 25")
        out["region_dist"]=[[r[0],int(r[1])] for r in cur.fetchall()]
    except Exception as e: out["region_dist"]="ERR "+str(e)
    c.close()
except Exception as e: out["db_err"]=str(e)[:300]
# 4) the autopull status-push function (to fix the 409)
try:
    ap=open("/opt/atlas/bin/atlas-autopull.sh",encoding="utf-8",errors="replace").read()
except Exception:
    f=glob.glob("/opt/atlas/**/atlas-autopull.sh",recursive=True)+glob.glob("/**/atlas-autopull.sh",recursive=True)
    ap=open(f[0]).read() if f else ""
m=re.search(r'(gh_put|status_push|push_status)[\s\S]{0,1200}', ap)
out["push_fn"]=m.group(0)[:1400] if m else "not found; autopull bytes="+str(len(ap))
out["autopull_path"]=glob.glob("/opt/atlas/**/atlas-autopull.sh",recursive=True)[:3]
# publish to a NEW status file (fresh name -> no stale-sha 409)
tok=os.environ.get("STATUS_TOKEN"); repo=os.environ.get("STATUS_REPO","cloudwalker171/atlas-manifests")
path="status/hetzner/srchunt-diag.json"
url="https://api.github.com/repos/%s/contents/%s"%(repo,path)
sha=None
try:
    rr=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Accept":"application/vnd.github+json"})
    sha=json.load(urllib.request.urlopen(rr,timeout=20)).get("sha")
except Exception: sha=None
body={"message":"srchunt diag","content":base64.b64encode(json.dumps(out,indent=1,default=str).encode()).decode(),"branch":"main"}
if sha: body["sha"]=sha
try:
    rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Content-Type":"application/json","Accept":"application/vnd.github+json"})
    urllib.request.urlopen(rq,timeout=25); print("srchunt-diag published")
except Exception as e:
    print("pub_err",str(e)[:160])
